var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…그래서 부상자 다수. 사망자는 민병대에 찍힌 알파트릭스 시큐리티의 임원 한 명이야.","JPN":"……で、怪我人多数。死亡者は民兵隊に狙われたアルファトリックスセキュリティの役員が一人。","ENG":"... so there were many who were injured, but the only one who died was Alphatrix's security director.","TWN":"…有多人受傷，死者只有一位，就是遭到民兵隊殺害的阿爾法崔克斯證券負責人。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"중상은 이 바보 한 명뿐이고.","JPN":"重傷はこのバカ一人だけ。","ENG":"And this idiot's the only one who was seriously injured.","TWN":"另外，重傷的就只有這個傻瓜。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"하하. 내가 통뼈라서 망정이지, 안 그랬으면 사망자가 한 명 더 늘어날 뻔했어.","JPN":"はは。俺の骨が丈夫でよかったぜ、じゃなけりゃあ死亡者が一人増えるところだったぞ。","ENG":"Haha. Just be glad I'm big-boned, or the death count would be two!","TWN":"哈哈，幸好我的骨骼驚奇，否則死亡人數可能要加一。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"으윽!?","JPN":"ううっ！？","ENG":"Ngh?!","TWN":"噢嗚！？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"},{"id":"L7_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"입만 살았지, 이 화상아. 엄폐도 제대로 안 하고 정신없이 쏘기만 하니까 당하지.","JPN":"よく言うわ、このドアホ。物陰に隠れもしないで撃ちまくるからやられるのよ。","ENG":"Shut up! You're hurt because you kept shooting like a mad man without any cover!","TWN":"你就剩一張嘴是吧？也不找掩護，在那邊瘋狂掃射，當然會受傷。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오늘 총 잡아 본 풋내기들도 너처럼은 안 하겠다.","JPN":"初めて銃を持つ素人もあんたよりはマシだわ。","ENG":"Even rookies these days wouldn't act like you.","TWN":"就算是第一次拿槍的新手也不會像你這樣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아니 그게, 그 파란 머리 아가씨에게 내버려 둘 수 없는 묘한 뭔가가 있었단 말이야.","JPN":"いや、それがな。あの青い髪のお嬢ちゃんにひっかかる妙な何かがあったんだ。","ENG":"But there was something odd about that blue-haired girl that I couldn't shake.","TWN":"不是，你聽我說，那個藍頭髮的小妹妹，我總覺得哪裡不對勁。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어떻게든 내 눈앞에서 치워야 한다거나……","JPN":"何としてでも俺の目の前から消さないといけないみたいな……","ENG":"As if something was telling me to kill it...","TWN":"不管怎麼樣一定要想辦法除掉她，否則後患無……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"으억!?","JPN":"うおっ！？","ENG":"Uargh?!","TWN":"噢嗚！？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"핑계 좀 지어대지 마, 핑계 좀. 오르카가 뭘 보고 배우겠어?","JPN":"言い訳はもういいよ、言い訳は。オルカが真似するでしょ。","ENG":"Enough of your excuses! What will Orca learn?","TWN":"少在那邊給我找理由，你這樣要怎麼教奧爾卡？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아니, 진짜 있었대도!","JPN":"いや、本当だって！","ENG":"I'm telling you the truth!","TWN":"吼唷，我是說真的啦！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"폭발이 일어났다는 뉴스는 저도 봤어요. 다행히 피해는 크지 않았나 보네요.","JPN":"爆発が起きたというニュースは私も見ました。幸い、被害は大きくはなかったようですね。","ENG":"I saw the news about the explosion being reported. Thank goodness the damages aren't that bad.","TWN":"我也有看到爆炸的新聞，幸好沒有造成太嚴重的傷亡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 우리가 갔을 때는 직원들이 이미 방송 듣고 모두 내뺀 뒤였거든.","JPN":"まあ、俺たちが到着したときには、すでにアナウンス聞いて職員全員が逃げた後だったんだ。","ENG":"Well, the staff had already heard the news and evacuated the place by the time we got there.","TWN":"我們去的時候，大部分員工都已經聽到廣播進行疏散。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"의뢰주에게 잔금은 안 줘도 괜찮다고 했어. 혹시 시말서 필요하면 얘기해.","JPN":"依頼主に残金はいらないって話しておいたわ。もし始末書が必要だったら言って。","ENG":"I told our client that she won't have to pay the rest. Let me know if you need me to write up a statement letter.","TWN":"我已經跟委託人說不需要支付尾款，有需要提交報告的話再跟我說。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"민병대인가 하는 녀석들은 결국 놓쳤으니까.","JPN":"民兵隊とかいうやつらは結局捕まえられなかったから。","ENG":"Because we failed to catch the Militia.","TWN":"至於民兵隊的傢伙，結果還是沒逮到。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그 후줄근한 아저씨, 이럴 줄 알았으면 사채업자 만나러 갔을 때 잡는 거였는데.","JPN":"あのくたびれたおじさん、こうなると知ってたら闇金業者に会いに行ったときに捕まえておけばよかったわ。","ENG":"If I had known, I would've caught that hobo when I first saw him with that loan shark.","TWN":"早知道這樣，去找放高利貸的時候，就應該逮住那個邋遢大叔的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 잘하셨어요. 두 분이 무리하셔야 할 만큼 저희 회사 자금 사정이……","JPN":"いいえ。十分です。お二人が無理しなければならないほど、会社の資金繰りが……","ENG":"No, you did a good job. The company is in such a bad financial situation that you two would have to...","TWN":"沒事的，你們做得很好。公司現在財政困難，只好讓你們二位這麼辛苦……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"후우……","JPN":"ふぅ……","ENG":"*Sigh*...","TWN":"哀……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"팍팍하구만.","JPN":"厳しいんだな。","ENG":"Man, that's rough.","TWN":"好沈重喔！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이터니움 값만 따져도 허리 부러지겠지. 이 작은 회사에 카운터만 몇 명이야, 대체.","JPN":"エタニウム代だけでも相当なものよね。この小さい会社にカウンターがうじゃうじゃしてるんだから、まったく。","ENG":"Just the cost of Eternium alone would sink this ship. How many Counters are there in this tiny company anyway?","TWN":"光是計算永恆之金的價值就已經很驚人，這麼小一間公司裡，到底是有多少位制裁者？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그보다 다이브한 쪽은 어때? 소식 좀 들어 온 거 있어?","JPN":"それよりダイブしてる方はどうなの？　連絡はあった？","ENG":"Besides that, what about the Divers? Did you hear anything from them?","TWN":"不過躍入那邊情況如何？有什麼消息嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"솔직히 말씀드리면… 교전이 벌어졌다는 신호 이후로 계속 통신 두절 상태예요.","JPN":"実は……交戦が始まったという信号を受信して以来、ずっと通信が途絶えたままなんです。","ENG":"To be honest... Comms have been cut off since they signaled us that a fight broke out.","TWN":"不瞞你說…收到開戰的訊號後，就一直是聯絡不上的狀態。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"관리국에 말해 봐도 상부 지침 때문에 움직일 수 없다는 대답만 들었고요.","JPN":"管理局に話してみても、上層部の指針で動けないの一点張りで。","ENG":"And all I heard from the Administration is that they can't move due to an order from the higher-ups.","TWN":"雖然有通知管理局，但他們只會說，因為上級的指示無法行動。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"상부 지침? 그럼 구조대 파견도 못해 주겠다는 거야?","JPN":"上層部の指針？　じゃあ、救助隊の派遣もできないということ？","ENG":"Orders from the higher-ups? You mean that they can't even send in a rescue team?","TWN":"上級的指示？意思是連派人力支援也無法嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네. 최고 관리자 회의가 끝나기 전까지는 비상 대기만 유지한다네요.","JPN":"はい。最高管理者の会議が終わるまでは非常待機のまま維持するらしいです。","ENG":"Yes. They stated that they must be on standby until the Supreme Administrator meeting has finished.","TWN":"對，在最高管理者會議結束前，只能維持緊急待命。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"크흠. 너무 걱정 말고 마음 편하게 먹어, 관리부장 씨.","JPN":"こほん。あんま心配しないで気を楽に持てよ、管理部長さん。","ENG":"Ahem...! Don't worry too much, Miss Kim.","TWN":"咳咳，管理部長，你別想太多，放寬心吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"우리 회사는 다들 한가닥 하잖아. 펜릴 쪽은 말할 것도 없고.","JPN":"うちの会社はみんな実力あるだろ？　フェンリル小隊の方は言うまでもない。","ENG":"You know everyone at this company can take care of themselves. Especially Fenrir Squad.","TWN":"我們公司的人可都是一等一的，芬里爾那邊就更不用說。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"지금은 고심도 좌표에 있느라 통신하기 어려운 거라고 생각해.","JPN":"今は高深度の座標にいて通信が繋がらないんだと思うぜ。","ENG":"I don't think we can get through to them because their coordinates are in the hyperdepths.","TWN":"我猜應該是因為現在在高深度座標裡，才會聯絡不上。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"일단 이 인간 말이 맞긴 해.","JPN":"こいつの言うとおりよ。","ENG":"Well, he's not wrong.","TWN":"這傢伙說的沒錯。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"다른 녀석들이면 모를까, 우리 회사 사람들은 믿고 기다릴 만하지.","JPN":"他のやつらならともかく、この会社の人たちは信じて待てる。","ENG":"I don't know about everyone else, but we can trust that nothing has happened to them yet.","TWN":"其他人我不敢說，但我相信我們公司的人是沒問題的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"고맙습니다. 사장님도 부재 중이신데 두 분까지 안 계셨으면 정말 막막했을 거예요.","JPN":"ありがとうございます。社長も留守なのにお二人までいなかったらどうなっていたことか。","ENG":"Thank you. With our boss gone... I would've been lost if you two hadn't been here.","TWN":"謝謝你們，老闆現在也不在，要是沒有你們二位，我真不知該如何是好。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"시말서 쓰라고 하지 않은 대신이라고 생각해.","JPN":"始末書の代わりだと思ったらいいのよ。","ENG":"Just think of it as instead of writing up that statement letter.","TWN":"就當作是代替提交報告吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"우린 정기편 타고 복귀할게. 알파트릭스도 자기들 시설이 공격받는대서 바쁜 것 같고.","JPN":"俺たちは定期便で復帰する。アルファトリックスも自分たちの施設が攻撃されてるとかで忙しいみたいだしな。","ENG":"We'll take the regular flight back. I think the Alphatrix people will be busy since their facility is under attack now.","TWN":"我們會搭定期航班回去，阿爾法崔克斯應該也忙著處理受到攻擊的事。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 수고하셨어요.","JPN":"わかりました。お疲れさまでした。","ENG":"Understood. Great work, the both of you.","TWN":"好的，辛苦你們了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"수고는 뭘. 오르카에게 편식하지 말라고 전해 줘.","JPN":"もう、大げさね。オルカに偏食するなと伝えておいて。","ENG":"As if. And tell Orca not to be picky with her food.","TWN":"沒什麼，幫我跟奧爾卡說不准挑食。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아. 나 다쳤다는 건 비밀이야. 오르카 녀석, 괜히 신경 쓸 테니까.","JPN":"あ。俺が怪我したってことは秘密だ。オルカのやつ、変に気を遣うだろうからな。","ENG":"One more thing, don't tell her I got hurt. She'll worry about me.","TWN":"對了，我受傷的事要保密喔，我怕奧爾卡會擔心。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"후우….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"哀哀…"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"관리부장, 힘들어?","JPN":"管理部長、疲れた？","ENG":"Hana, are you sad?","TWN":"管理部長，你累了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아. 오르카 씨.","JPN":"あ。オルカさん。","ENG":"Oh, Orca.","TWN":"喔，奧爾卡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"힘들기는요. 현장에 나가 있는 직원 분들이 걱정이죠.","JPN":"疲れていません。現場に出ている職員の方々が心配ですね。","ENG":"No, not at all. I'm just worried about our employees out in the field.","TWN":"我有什麼好累的，我是擔心在現場出勤的員工。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"나는 따뜻하고 달콤한 걸 먹으면 마음이 편안해져.","JPN":"オルカは温かくて甘いものを食べると落ち着く。","ENG":"I feel better whenever I have something warm and sweet.","TWN":"我只要吃熱熱的甜點心情就會變好喔。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"관리부장도 같이 마시멜로를 먹자. 마음이 편해질 거야.","JPN":"管理部長も一緒にマシュマロ食べよう。気持ちが楽になる。","ENG":"Eat a marshmallow with me. It'll make you feel better too.","TWN":"你也一起吃棉花糖吧，心情會變好喔。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"오늘치 마시멜로는 벌써 다 떨어졌는걸요?","JPN":"今日分のマシュマロはもうありませんよ？","ENG":"But you already ate all the marshmallows for today.","TWN":"可是今天份的棉花糖都吃完咧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…없어? 마시멜로가?","JPN":"……ない？　マシュマロが？","ENG":"There's... no more marshmallows?","TWN":"…沒了嗎？我的棉花糖？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네. 아침에 와서 전부 드셨잖아요.","JPN":"はい。朝来て全部食べましたからね。","ENG":"Mm-hmm. You ate them all this morning.","TWN":"對啊，你早上來公司後不就吃光了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오늘은 왠지 가슴이 두근두근해. 꼭 뭔가가 가까워지는 것처럼.","JPN":"今日はなんだか胸がドキドキする。まるで何かが近づいてるみたいに。","ENG":"My heart is feeling funny today for some reason. Like something is getting close.","TWN":"不知道為什麼，今天心跳得特別快呢，好像有什麼事會發生一樣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니까 내일치 마시멜로를 먹자.","JPN":"だから明日分のマシュマロを食べよう。","ENG":"So let's eat tomorrow's marshmallows today.","TWN":"不如就先把明天份的棉花糖吃掉吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"지금 먹으면 내일은 또 마시멜로를 못 먹게 될 텐데요?","JPN":"今食べると明日はまたマシュマロを食べられなくなりますけど。","ENG":"But then you won't have any marshmallows for tomorrow, Orca.","TWN":"你現在吃掉的話，那明天又沒得吃咧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"괜찮아. 내일은 내일의 오르카에게 맡기면 돼.","JPN":"大丈夫。明日は明日のオルカに任せればいい。","ENG":"That's okay. I'll let tomorrow's me worry about that.","TWN":"沒關係，明天的事就交給明天的奧爾卡去煩惱吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"찰리 씨에게 배운 말이죠? 아무리 떼를 써도 안 되는 건 안 돼요.","JPN":"チャーリーさんから教わったでしょう？　いくら駄々をこねてもダメなものはダメです。","ENG":"You learned that from Charlie, didn't you? No matter how much you beg, the answer is no.","TWN":"你這話是跟查理學的吧？耍賴也沒用，不行就是不行。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"어째서지?","JPN":"どうして？","ENG":"But why?","TWN":"為什麼？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"떠날 때 제시카 씨가 부탁하셨거든요. 편식하는 습관을 고치기 위해 협조해 달라고요.","JPN":"ジェシカさんから出発するときに頼まれました。偏食する習慣を直すために協力してほしいと。","ENG":"Jessica made me promise when she left that I'd help her fix your bad habits.","TWN":"潔西卡離開的時候有拜託我，請我幫忙改掉你挑食的壞習慣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"침식체를 해치워도 안 돼?","JPN":"侵食体をやっつけてもダメ？","ENG":"Then can I go out and kill C.O.s?","TWN":"那消滅侵蝕體也不可以嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"현장에 나가는 건 금지예요.","JPN":"現場に出るのは禁止です。","ENG":"You're not allowed to go out.","TWN":"你不可以出去。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"오르카 씨는 지금 휴가 중이잖아요? 사장님 지시를 어기면…","JPN":"オルカさんは今お休み中でしょう？　社長の指示に従わないと……","ENG":"You're on vacation, Orca. And if you don't follow Boss's orders─","TWN":"你現在不是在放假嗎？要是違背老闆的命令…"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"오랜만입니다, 관리부장님. 역시 회사에는 두 분만 남아 계셨군요.","JPN":"お久しぶりです、管理部長様。やはり会社にはお二人だけ残っていたのですね。","ENG":"Long time no see, Miss Kim. I see you two are the only ones here.","TWN":"好久不見，管理部長。公司果然只剩下你們二個而已。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 베로니카 씨!","JPN":"あら、ベロニカさん！","ENG":"Oh my, Miss Veronica!","TWN":"哇，是貝洛妮卡！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"안 그래도 오르카 씨가 가슴이 두근거렸다던데, 베로니카 씨 때문이었나 봐요.","JPN":"オルカさんが胸がドキドキすると言っていたんですが、ベロニカさんのことだったんですね。","ENG":"Orca was just talking about how her heart was feeling funny. Maybe it was because of you, Miss Veronica.","TWN":"奧爾卡剛剛還說她心跳得很快，是因為貝洛妮卡的關係嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그라운드 원에는 어쩐 일이세요? 혹시 근처 태스크포스에 고용되신 건가요?","JPN":"グラウンド・ワンにはどんなご用ですか？　もしかしてこの辺りのタスクフォースに雇われたのですか？","ENG":"What brings you to Ground One? Did you get hired to one of the TASKFORCE nearby?","TWN":"你怎麼會來G1？有特遣勢力雇用你嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아뇨. 오늘 온 건 개인적인 용무를 위해서랍니다.","JPN":"いいえ。今日は個人的な用務のために来ました。","ENG":"No. I'm here on a personal matter.","TWN":"不是，我今天來是因為私事。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"잠시 사장님을 뵈었으면 합니다. 부디 허락해 주시길.","JPN":"社長と少しお話ししたいのですが。どうか許可を。","ENG":"I wish to see Boss. Would that be okay?","TWN":"我想見一下老闆，還請幫忙通知。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그건 조금 어렵겠네요. 저도 사장님께서 지금 어디 계신지 들은 게 없어서요.","JPN":"それは少々難しいですね。私も社長がどちらに行かれたのか伺っていなくて。","ENG":"I'm afraid that'll be difficult. I have no clue where he is right now.","TWN":"這可能有困難欸，我也不知道老闆現在人在哪裡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럼 잠시 집무실을 확인해 봐도 괜찮을까요?","JPN":"それでは少し執務室を確認してもよろしいでしょうか？","ENG":"Then would it be okay if I looked around the office?","TWN":"那我可以去辦公室看一下嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"집무실을요?","JPN":"執務室をですか？","ENG":"The office?","TWN":"辦公室嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"관리부장, 물러서.","JPN":"管理部長、下がって。","ENG":"Hana, get back.","TWN":"管理部長，小心！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"오르카 씨? 갑자기 왜 그렇게 무서운 표정을 지으세요?","JPN":"オルカさん？　突然どうしたのですか？　顔が怖いですよ。","ENG":"Orca? Why are you suddenly making that scary face?","TWN":"奧爾卡？你的表情怎麼突然變得那麼凶狠？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내 안의 오르카가 알려 줬어.","JPN":"私の中のオルカが教えてくれた。","ENG":"The Orca inside me told me.","TWN":"我裡面的奧爾卡告訴我的，"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"저번에 봤을 때와 다르대. 피비린내가 진해졌어.","JPN":"この前に会った時とは違うって。血の匂いが濃くなってる。","ENG":"She says she's different from the last time we saw her. She stinks of blood.","TWN":"和上次見面的感覺不一樣，血腥味變得很濃。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"피, 피비린내라뇨. 마시멜로를 못 먹어서 코가 너무 예민해진 거겠죠.","JPN":"ち、血の匂いって。マシュマロを食べられなくてきっと鼻が敏感になってるんですよ。","ENG":"B-blood? It must be your sense of smell getting sensitive because you didn't have any marshmallows.","TWN":"血…血腥味？是因為沒棉花糖吃，鼻子才會變得那麼敏感吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그렇죠, 베로니카 씨?","JPN":"ね？　ベロニカさん。","ENG":"Right, Miss Veronica?","TWN":"你說是不是，貝洛妮卡？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"베로니카 씨……?","JPN":"ベロニカさん……？","ENG":"Miss Veronica...?","TWN":"貝洛妮卡……？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"관리부장님. 저는 주인님의 구상이 난관에 부딪쳤다는 이야기를 듣고 왔습니다.","JPN":"管理部長様。私はご主人様の構想が難関に突き当たったという話を聞いて参りました。","ENG":"Miss Kim, I heard Master's plans have hit a brick wall. That's why I'm here.","TWN":"管理部長，我來找主人，是聽說他的計畫遇到一些瓶頸。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"오늘 이후로 제가 했던 행동을 나무라실 수도 있고, 저를 혐오하게 되실 수도 있어요.","JPN":"今後、私の行動を責めるようになるかもしれませんし、私のことを憎むようになるかもしれません。","ENG":"After today, you can scold me for what I'll be done, and you may even despise me.","TWN":"過了今天，主人很可能會責備我的行為，會討厭我。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 그건 모두 저를 수렁에서 건져 주신 주인님을 위해서랍니다.","JPN":"ですが、それはすべて、私を泥沼から救ってくださったご主人様のためなのです。","ENG":"However, this is all for Master, who saved me from slough.","TWN":"但這一切，都是為了將我從泥沼裡拉拔出來的主人。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"베로니카 씨, 지금 무슨","JPN":"ベロニカさん、何の","ENG":"Miss Veronica... What","TWN":"貝洛妮卡，你這是…"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"말씀……을……?","JPN":" こと……を……？","ENG":" are... you...?","TWN":" 什麼……意思……？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L7_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이번에는 얕게 베었어. 다음은 더 깊게 벨 거야.","JPN":"浅く斬った。次はもっと深く斬る。","ENG":"That cut was shallow on purpose. The next cut will be deeper.","TWN":"我這次下手比較輕，下次可不會手下留情。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 경고의 뜻으로 받아들이겠습니다.","JPN":"はい。警告として受け止めましょう。","ENG":"All right. I'll take that as a warning then.","TWN":"是，我會將它視為是警告之意。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"무슨 일을 할 건지 말하면 오르카도, 나도 도와 줄 수 있어.","JPN":"何をするのか話してくれたらオルカも、私も手伝ってあげられる。","ENG":"Orca and I could help you if you tell us what you're going to do.","TWN":"你可以說你想做什麼，奧爾卡和我都可以幫你。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 아무 말 없이 자기 혼자 저지르는 건 싫어.","JPN":"でも何も言わないで自分一人でやるのはよくない。","ENG":"But we don't like it if you do something without telling us.","TWN":"但我不喜歡什麼都不說就自己行動。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"어째서죠? 주인님을…. 아니, 사장님을 위해서라고 말씀드렸을 텐데요.","JPN":"どうしてですか？　ご主人様を……いいえ、社長のためとお話ししたはずです。","ENG":"What do you mean? I told you this is for Master, I mean, Boss.","TWN":"怎麼會呢？我剛應該有說，這一切都是為了主人…不，是為了老闆。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금 베로니카의 눈은 아저씨와 닮았으니까.","JPN":"今のベロニカの目はおじさんと似てるから。","ENG":"Because your eyes have the same look as Eddie's.","TWN":"貝洛妮卡現在的眼神和大叔很像。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"나에게는 살라고 했으면서…. 자기는 죽어도 괜찮다고 하는 눈.","JPN":"私には生きろって言っておいて……自分は死んでもいいっていう目。","ENG":"The same look as when he told me to live... but didn't care if he died.","TWN":"叫我要活下去…自己死掉也無所謂的眼神。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니까, 나는 베로니카를 막을 거야.","JPN":"だから、私はベロニカを止める。","ENG":"That's why I'm going to stop Veronica.","TWN":"我會阻止貝洛妮卡的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……동물적이군요. 뛰어난 직감입니다.","JPN":"……動物的ですね。優れた直感です。","ENG":"...What excellent animal senses you have.","TWN":"……本能的想法嗎？直覺很準確呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇게까지 말씀하신다면, 알겠습니다.","JPN":"そこまでおっしゃるのなら、わかりました。","ENG":"If you insist, then.","TWN":"既然你這麼說，那好吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하오나 신변에 위해를 가할 수 있는 점, 모쪼록 헤아려 주시길.","JPN":"ですが身の回りに危害が加わることもあるということを何卒ご容赦ください。","ENG":"However, please keep in mind that I could harm you.","TWN":"不過，萬一我危害到身邊人，那還敬請見諒。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};